package main

import "fmt"

func sortBytes(b []byte) {
	n := len(b)
	for i := 0; i < n; i++ {
		for j := i + 1; j < n; j++ {
			if b[j] < b[i] {
				b[i], b[j] = b[j], b[i]
			}
		}
	}
}

func permute(s string) []string {
	b := []byte(s)
	sortBytes(b)
	n := len(b)
	used := make([]bool, n)
	cur := make([]byte, 0, n)
	var out []string
	var dfs func()
	dfs = func() {
		if len(cur) == n {
			out = append(out, string(cur))
			return
		}
		for i := 0; i < n; i++ {
			if used[i] {
				continue
			}
			used[i] = true
			cur = append(cur, b[i])
			dfs()
			cur = cur[:len(cur)-1]
			used[i] = false
		}
	}
	dfs()
	return out
}

func main() {
	fmt.Println(permute("abc"))
}
